from typing import Optional, List
from leann.api import LeannBuilder
from pathlib import Path
import json

def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    # Check if JSON file exists
    if not Path(json_file_path).exists():
        raise FileNotFoundError(f"JSON file not found at {json_file_path}")

    # Load JSON data
    try:
        with open(json_file_path) as f:
            data = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("missing required field")

    # Validate text_field presence in all documents
    missing = [doc for doc in data if text_field not in doc]
    if missing:
        raise ValueError("missing required field")

    # Prepare documents for LeannBuilder
    documents = []
    for doc in data:
        # Assume each document has an 'id' field (per problem statement)
        metadata = {}
        if metadata_fields is None:
            # Include all fields except text_field
            metadata = {k: v for k, v in doc.items() if k != text_field}
        else:
            # Include specified metadata fields
            metadata = {field: doc[field] for field in metadata_fields if field in doc}

        new_doc = {
            'id': doc['id'],
            'text': doc[text_field],
            'metadata': metadata
        }
        documents.append(new_doc)

    # Build the index
    builder = LeannBuilder(backend_module_name=backend_name)
    builder.build(documents, index_path=index_path)

    return index_path

