from typing import List, Optional
from leann.api import LeannSearcher, SearchResult
from collections import defaultdict

def search_multiple_indexes(
    index_paths: List[str],
    query: str,
    top_k_per_index: int = 3
) -> Dict[str, List[SearchResult]]:
    if not index_paths:
        raise ValueError("index_paths cannot be empty")
    results = {}
    for path in index_paths:
        searcher = LeannSearcher(path)
        res = searcher.search(query, top_k=top_k_per_index)
        results[path] = res
    return results

def merge_search_results(
    results_by_index: Dict[str, List[SearchResult]],
    global_top_k: int = 10,
    deduplicate: bool = True
) -> List[SearchResult]:
    merged = []
    for res_list in results_by_index.values():
        merged.extend(res_list)
    merged.sort(key=lambda x: x.score, reverse=True)
    if deduplicate:
        seen = set()
        unique = []
        for r in merged:
            text = r.text
            if text not in seen:
                unique.append(r)
                seen.add(text)
        merged = unique
    return merged[:global_top_k]

