from typing import List, Any, Optional
from pathlib import Path
import json
from collections import defaultdict, Counter

def get_index_statistics(index_path: str) -> dict[str, Any]:
    meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"LEANN metadata file not found at {meta_path}")
    with open(meta_path) as f:
        passages = json.load(f)
    total = len(passages)
    fields = set()
    field_counts = defaultdict(Counter)
    for passage in passages:
        meta = passage.get("metadata", {})
        for k in meta:
            fields.add(k)
            field_counts[k][meta[k]] += 1
    return {
        "total_passages": total,
        "metadata_fields": sorted(fields),
        "field_value_counts": {k: dict(v) for k, v in field_counts.items()},
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"LEANN metadata file not found at {meta_path}")
    with open(meta_path) as f:
        passages = json.load(f)
    total = len(passages)
    covered = 0
    field_coverages = {}
    missing_fields = []
    for passage in passages:
        meta = passage.get("metadata", {})
        if all(field in meta for field in required_fields):
            covered += 1
    for field in required_fields:
        count = sum(1 for p in passages if field in p.get("metadata", {}))
        field_coverages[field] = (count / total) * 100
        if count == 0:
            missing_fields.append(field)
    return {
        "coverage_percentage": (covered / total) * 100,
        "field_coverage": field_coverages,
        "missing_fields": missing_fields,
    }

