def export_index_metadata(index_path: str, output_file: str) -> dict[str, Any]:
    meta_path = f"{index_path}.meta.json"
    if not Path(meta_path).exists():
        raise FileNotFoundError("Index metadata file not found")

    with open(meta_path) as f:
        meta = json.load(f)

    passages = []
    for source in meta.get("passage_sources", []):
        source_type = source.get("type")
        path = source.get("path")
        if source_type == "jsonl":
            with open(path) as fh:
                for line_num, line in enumerate(fh, 1):
                    try:
                        data = json.loads(line.strip())
                        passages.append({"id": data.get("id"), "text": data.get("text")})
                    except Exception:
                        continue
        elif source_type == "csv":
            import csv
            with open(path) as fh:
                reader = csv.DictReader(fh)
                for row in reader:
                    passages.append({"id": row["id"], "text": row["text"]})
        else:
            # Handle other types if needed, but proceed for now
            pass

    export_data = {
        "version": meta.get("version", "1.0"),
        "backend_module": meta.get("backend_module"),
        "backend_kwargs": meta.get("backend_kwargs", {}),
        "passages": passages,
    }

    with open(output_file, "w") as f:
        json.dump(export_data, f, indent=2)

    return {
        "exported_passages": len(passages),
        "output_file": output_file,
        "status": "success",
    }

def import_index_from_metadata(
    export_file: str, index_path: str, backend_name: str = "hnsw"
) -> dict[str, Any]:
    if not Path(export_file).exists():
        raise FileNotFoundError("Export file not found")

    with open(export_file) as f:
        data = json.load(f)

    if not data.get("version") or not data.get("passages") or not data.get("backend_module"):
        raise ValueError("Invalid export file format")

    passages = data["passages"]
    backend_module_name = data["backend_module"]
    backend_kwargs = data.get("backend_kwargs", {})

    passage_manager = PassageManager()
    for passage in passages:
        passage_manager.add_passage(passage["id"], passage["text"])

    builder = LeannBuilder(backend_module_name, **backend_kwargs)
    builder.build(passage_manager, index_path)

    return {
        "index_path": index_path,
        "passages_imported": len(passages),
        "status": "success",
    }

