from typing import List, Any
from leann.api import LeannSearcher, SearchResult


def search_with_score_normalization(
    index_path: str,
    query: str,
    normalize_to_range: tuple = (0.0, 1.0),
    top_k: int = 10
) -> List[SearchResult]:
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index file not found")

    min_range, max_range = normalize_to_range
    if min_range >= max_range:
        raise ValueError("min must be less than max")

    results = searcher.search(query, top_k=top_k)
    raw_scores = [r.score for r in results]
    min_raw = min(raw_scores)
    max_raw = max(raw_scores)

    if min_raw == max_raw:
        normalized_scores = [min_range] * len(results)
    else:
        normalized_scores = [
            min_range + (s - min_raw) * (max_range - min_range) / (max_raw - min_raw)
            for s in raw_scores
        ]

    normalized_results = []
    for i, result in enumerate(results):
        normalized_results.append(
            SearchResult(
                id=result.id,
                score=normalized_scores[i]
            )
        )

    return normalized_results

